async function sendGridEmail(request) {
  const apiKey = process.env.SENDGRID_API_KEY;
  if (!apiKey) {
    return new Response(JSON.stringify({ error: 'No SendGrid API Key found' }), { status: 500 });
  }
  const response = await fetch(`https://api.sendgrid.com/v3/mail/send`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`
    },
    body: JSON.stringify({
      from: { email: process.env.SENDGRID_FROM_EMAIL, name: process.env.SENDGRID_FROM_NAME },
      subject: request.headers.get('X-EMAIL-SUBJECT'),
      text: request.headers.get('X-EMAIL-BODY')
    })
  });
  return new Response(JSON.stringify({ status: response.status }), { status: response.status });
}

async function stripePayment(request) {
  const apiKey = process.env.STRIPE_API_KEY;
  if (!apiKey) {
    return new Response(JSON.stringify({ error: 'No Stripe API Key found' }), { status: 500 });
  }
  const body = await request.json();
  const response = await fetch('https://api.stripe.com/v1/checkout/sessions', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`
    },
    body: JSON.stringify(body)
  });
  return new Response(JSON.stringify({ status: response.status }), { status: response.status });
}